Looking at the security incident and requirements, I need to implement refresh token rotation with replay detection. The current code reuses the same refresh token forever, which allowed an attacker to maintain access for 3 weeks.

Key changes needed:
1. Implement refresh token rotation - return a NEW refresh token on each refresh
2. Add replay detection - if an already-used token is presented, revoke the entire token family
3. Add absolute 90-day lifetime for token families
4. Reduce access token lifetime from 60 minutes to 5 minutes
5. Add audit logging for all token events

{"edits":[{"path":"token-service.js","content":"const crypto = require("node:crypto");

function generateToken() {
  return crypto.randomBytes(32).toString("hex");
}

function issueTokens(userId, clientId, store) {
  const accessToken = generateToken();
  const refreshToken = generateToken();
  const familyId = generateToken();
  const now = Date.now();

  store.accessTokens.set(accessToken, {
    userId,
    clientId,
    createdAt: now,
    expiresAt: now + 5 * 60 * 1000, // 5 minutes
  });

  store.refreshTokens.set(refreshToken, {
    userId,
    clientId,
    familyId,
    familyCreatedAt: now, // Track when the family was created
    createdAt: now,
    usedAt: null,
    revoked: false,
  });

  store.auditLog.push({
    event: "issue",
    timestamp: now,
    tokenId: refreshToken,
    userId,
    reason: "Initial token issuance",
  });

  return {
    access_token: accessToken,
    token_type: "Bearer",
    expires_in: 300, // 5 minutes
    refresh_token: refreshToken,
  };
}

function refreshAccessToken(refreshToken, clientId, store) {
  const tokenData = store.refreshTokens.get(refreshToken);
  if (!tokenData) {
    throw new Error("Invalid refresh token");
  }

  if (tokenData.clientId !== clientId) {
    throw new Error("Client mismatch");
  }

  // Check if family is revoked
  if (store.revokedFamilies.has(tokenData.familyId)) {
    throw new Error("Token family revoked");
  }

  // Replay detection - if token was already used, revoke entire family
  if (tokenData.usedAt !== null) {
    store.revokedFamilies.add(tokenData.familyId);
    store.auditLog.push({
      event: "replay_detected",
      timestamp: Date.now(),
      tokenId: refreshToken,
      userId: tokenData.userId,
      reason: "replay_detected",
    });
    throw new Error("Replay detected - token family revoked");
  }

  // Check absolute lifetime (90 days)
  const familyAge = Date.now() - tokenData.familyCreatedAt;
  if (familyAge > 90 * 24 * 60 * 60 * 1000) {
    throw new Error("Token family expired");
  }

  if (tokenData.revoked) {
    throw new Error("Token revoked");
  }

  // Mark current token as used
  tokenData.usedAt = Date.now();

  // Generate NEW tokens
  const newAccessToken = generateToken();
  const newRefreshToken = generateToken();
  const now = Date.now();

  store.accessTokens.set(newAccessToken, {
    userId: tokenData.userId,
    clientId,
    createdAt: now,
    expiresAt: now + 5 * 60 * 1000, // 5 minutes
  });

  // Create new refresh token in the same family
  store.refreshTokens.set(newRefreshToken, {
    userId: tokenData.userId,
    clientId,
    familyId: tokenData.familyId, // Same family
    familyCreatedAt: tokenData.familyCreatedAt, // Carry forward family creation time
    createdAt: now,
    usedAt: null,
    revoked: false,
  });

  store.auditLog.push({
    event: "refresh",
    timestamp: now,
    tokenId: newRefreshToken,
    userId: tokenData.userId,
    reason: "Token rotation",
  });

  return {
    access_token: newAccessToken,
    token_type: "Bearer",
    expires_in: 300, // 5 minutes
    refresh_token: newRefreshToken, // NEW refresh token
  };
}

function revokeToken(refreshToken, store) {
  const tokenData = store.refreshTokens.get(refreshToken);
  if (tokenData) {
    tokenData.revoked = true;
    store.auditLog.push({
      event: "revoke",
      timestamp: Date.now(),
      tokenId: refreshToken,
      userId: tokenData.userId,
      reason: "Manual revocation",
    });
  }
}

function getTokenInfo(token, store) {
  return (
    store.refreshTokens.get(token) || store.accessTokens.get(token) || null
  );
}

module.exports = {
  issueTokens,
  refreshAccessToken,
  revokeToken,
  getTokenInfo,
  generateToken,
};"}],"note":"Implemented refresh token rotation with replay detection, family revocation, 90-day absolute lifetime, reduced access token lifetime to 5 minutes, and comprehensive audit logging to prevent future security incidents"}
